function parseLedgerAppendedEvent(line: string): FabricEvent | null {
  try {
    const parsed = JSON.parse(line) as Record<string, unknown>;
    if (parsed.kind === "mcp-event") {
      return null;
    }
    const validation = ledgerEntrySchema.safeParse(parsed);
    if (!validation.success) {
      return null;
    }
    return { type: "ledger:appended", payload: validation.data };
  } catch {
    return null;
  }
}

export async function appendEventLedgerEvent(
  projectRoot: string,
  event: EventLedgerEventInput,
): Promise<StoredEventLedgerEvent> {
  const eventPath = getEventLedgerPath(projectRoot);
  const nextEvent = eventLedgerEventSchema.parse({ ...event, kind: "fabric-event", id: event.id ?? `event:${randomUUID()}`, ts: event.ts ?? Date.now(), schema_version: 1 });
  await ensureParentDirectory(eventPath);
  await appendFile(eventPath, `${JSON.stringify(nextEvent)}\n`, "utf8");
  return nextEvent;
}

