server.registerResource(
  "bootstrap README",
  AGENTS_MD_RESOURCE_URI,
  { description: "L0 fabric bootstrap file — global agent instructions for this project", mimeType: "text/markdown" },
  async (_uri: URL) => {
    const projectRoot = process.env.FABRIC_PROJECT_ROOT ?? process.cwd();
    const content = await readFile(join(projectRoot, ".fabric", "bootstrap", "README.md"), "utf8");
    return { contents: [{ uri: AGENTS_MD_RESOURCE_URI, mimeType: "text/markdown", text: content }] };
  },
);

async function writeDefaultBootstrap(projectRoot: string): Promise<void> {
  const path = join(projectRoot, ".fabric", "bootstrap", "README.md");
  await ensureParentDirectory(path);
  await atomicWriteText(path, "# Fabric Bootstrap\n\nProject-specific Fabric bootstrap notes.\n");
}

